final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: 'CloudWatch Dashboard for monitoring NAT Gateway VPC Flow Logs with Logs Insights widgets for top source IPs by outbound traffic and rejected connections.'

Parameters:
  LogGroupName:
    Type: String
    Default: '/aws/vpc/nat-gateway-flowlogs'
    Description: 'Name of the CloudWatch Logs group containing VPC Flow Logs (e.g., /aws/vpc/nat-gateway-flowlogs).'
  DashboardName:
    Type: String
    Default: NATGatewayFlowLogsDashboard
    Description: 'Name of the CloudWatch Dashboard.'

Resources:
  NATGatewayFlowLogsDashboard:
    Type: AWS::CloudWatch::Dashboard
    Properties:
      DashboardName: !Ref DashboardName
      DashboardBody: !Sub |
        {
          "widgets": [
            [
              {
                "type": "log",
                "properties": {
                  "queries": [
                    {
                      "id": "q1",
                      "queryString": "fields @timestamp, srcAddr, bytes, action, interfaceId | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(bytes) as totalBytes by srcAddr | sort totalBytes desc | limit 10",
                      "logGroups": [
                        {
                          "logGroupName": "${LogGroupName}"
                        }
                      ]
                    }
                  ],
                  "view": "table",
                  "width": 6,
                  "height": 6,
                  "title": "Top 10 Source IPs by Outbound Bytes",
                  "start": "P1D",
                  "end": "PT0S"
                }
              },
              {
                "type": "log",
                "properties": {
                  "queries": [
                    {
                      "id": "q2",
                      "queryString": "fields @timestamp, srcAddr, packets, action, interfaceId | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(packets) as totalPackets by srcAddr | sort totalPackets desc | limit 10",
                      "logGroups": [
                        {
                          "logGroupName": "${LogGroupName}"
                        }
                      ]
                    }
                  ],
                  "view": "table",
                  "width": 6,
                  "height": 6,
                  "title": "Top 10 Source IPs by Outbound Packets",
                  "start": "P1D",
                  "end": "PT0S"
                }
              },
              {
                "type": "log",
                "properties": {
                  "queries": [
                    {
                      "id": "q3",
                      "queryString": "fields @timestamp, srcAddr, packets, action, interfaceId | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(packets) as rejectedPackets by srcAddr | sort rejectedPackets desc | limit 10",
                      "logGroups": [
                        {
                          "logGroupName": "${LogGroupName}"
                        }
                      ]
                    }
                  ],
                  "view": "table",
                  "width": 6,
                  "height": 6,
                  "title": "Top 10 Source IPs by Rejected Packets",
                  "start": "P1D",
                  "end": "PT0S"
                }
              },
              {
                "type": "log",
                "properties": {
                  "queries": [
                    {
                      "id": "q4",
                      "queryString": "fields @timestamp, srcAddr, bytes, action, interfaceId | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(bytes) as rejectedBytes by srcAddr | sort rejectedBytes desc | limit 10",
                      "logGroups": [
                        {
                          "logGroupName": "${LogGroupName}"
                        }
                      ]
                    }
                  ],
                  "view": "table",
                  "width": 6,
                  "height": 6,
                  "title": "Top 10 Source IPs by Rejected Bytes",
                  "start": "P1D",
                  "end": "PT0S"
                }
              }
            ]
          ]
        }

Outputs:
  DashboardUrl:
    Description: 'URL to access the CloudWatch Dashboard.'
    Value: !Sub 'https://${AWS::Region}.console.aws.amazon.com/cloudwatch/home?region=${AWS::Region}#dashboards:name=${DashboardName}'

